// Optional helper macros.
#define WL6_MAP_AT(x,y) pgm_read_byte(&world_map[(uint16_t)(y) * 64 + (uint16_t)(x)])
#define WL6_TEXEL(tex,x,y) pgm_read_byte(&wall_textures[((uint16_t)(tex) * 1024) + ((uint16_t)(y) * 32) + (uint16_t)(x)])
#define WL6_COLOR565(idx) pgm_read_word(&wolf3d_palette_rgb565[(uint8_t)(idx)])
#define WL6_IS_DOOR(t) ((t) == WL6_TILE_DOOR_GREEN || (t) == WL6_TILE_DOOR_LOCKED || (t) == WL6_TILE_DOOR_ELEVATOR)
#define WL6_IS_TEXTURE_TILE(t) ((t) > 0 && (t) <= WL6_NUM_WALL_TEXTURES)
#define WL6_IS_EXIT(t) ((t) == WL6_TILE_EXIT)
